SELECT * from t_asset_depreciation



        and DATE_FORMAT(depreciation_date, '%Y-%m-%d') >= #{queryForm.startTime}


        and DATE_FORMAT(depreciation_date, '%Y-%m-%d') <= #{queryForm.endTime}



        AND ( INSTR(depreciation_no,#{queryForm.keywords}))


        AND enterprise_id = #{queryForm.enterpriseId}



    ORDER BY create_time DESC
